<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Kanban Board</title>
    <style>
        :root {
            --bg-color: #f4f7f9;
            --column-bg: #ebedf0;
            --card-bg: #ffffff;
            --text-main: #333;
            --text-muted: #666;
            --accent: #007bff;
            --danger: #dc3545;
            --shadow: 0 2px 5px rgba(0,0,0,0.1);
        }

        body {
            font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
            background-color: var(--bg-color);
            color: var(--text-main);
            margin: 0;
            padding: 20px;
            display: flex;
            flex-direction: column;
            align-items: center;
        }

        /* Input Section */
        .input-container {
            width: 100%;
            max-width: 800px;
            margin-bottom: 30px;
            display: flex;
            gap: 10px;
        }

        #new-card {
            flex-grow: 1;
            padding: 12px 15px;
            border: 1px solid #ccc;
            border-radius: 6px;
            font-size: 1rem;
            outline: none;
        }

        #new-card:focus {
            border-color: var(--accent);
        }

        #add-card {
            padding: 10px 20px;
            background-color: var(--accent);
            color: white;
            border: none;
            border-radius: 6px;
            cursor: pointer;
            font-weight: bold;
            transition: background 0.2s;
        }

        #add-card:hover {
            background-color: #0056b3;
        }

        /* Board Layout */
        .board {
            display: flex;
            gap: 20px;
            width: 100%;
            max-width: 1200px;
            align-items: flex-start;
            justify-content: center;
        }

        .column {
            background-color: var(--column-bg);
            border-radius: 8px;
            width: 350px;
            min-height: 400px;
            display: flex;
            flex-direction: column;
            padding: 10px;
            box-shadow: var(--shadow);
        }

        .column-header {
            padding: 10px;
            font-weight: bold;
            font-size: 1.1rem;
            display: flex;
            justify-content: space-between;
            align-items: center;
            user-select: none;
        }

        .count {
            background: #ddd;
            padding: 2px 8px;
            border-radius: 12px;
            font-size: 0.85rem;
            color: var(--text-muted);
        }

        /* Card Container */
        .card-list {
            flex-grow: 1;
            min-height: 100px; /* Ensures drop target is visible even when empty */
        }

        /* Card Styling */
        .card {
            background-color: var(--card-bg);
            padding: 15px;
            margin-bottom: 10px;
            border-radius: 6px;
            box-shadow: var(--shadow);
            cursor: grab;
            display: flex;
            justify-content: space-between;
            align-items: center;
            word-break: break-word;
            transition: transform 0.1s, opacity 0.1s;
        }

        .card:active {
            cursor: grabbing;
        }

        .card.dragging {
            opacity: 0.5;
            transform: scale(0.95);
        }

        .card-text {
            flex-grow: 1;
            margin-right: 10px;
        }

        .card-del {
            background: none;
            border: none;
            color: var(--danger);
            font-size: 1.2rem;
            cursor: pointer;
            padding: 0 5px;
            line-height: 1;
            opacity: 0.6;
            transition: opacity 0.2s;
        }

        .card-del:hover {
            opacity: 1;
        }

        /* Drag Over Effect */
        .column.drag-over {
            background-color: #dfe3e6;
            outline: 2px dashed var(--accent);
        }

        @media (max-width: 1000px) {
            .board {
                flex-direction: column;
                align-items: center;
            }
            .column {
                width: 90%;
            }
        }
    </style>
</head>
<body>

    <div class="input-container">
        <input type="text" id="new-card" placeholder="Enter task title..." autocomplete="off">
        <button id="add-card">Add Card</button>
    </div>

    <div class="board">
        <!-- To Do Column -->
        <div class="column" id="col-todo">
            <div class="column-header">
                <span>To Do</span>
                <span class="count">0</span>
            </div>
            <div class="card-list" ondragover="handleDragOver(event)" ondragleave="handleDragLeave(event)" ondrop="handleDrop(event)">
                <!-- Cards go here -->
            </div>
        </div>

        <!-- Doing Column -->
        <div class="column" id="col-doing">
            <div class="column-header">
                <span>Doing</span>
                <span class="count">0</span>
            </div>
            <div class="card-list" ondragover="handleDragOver(event)" ondragleave="handleDragLeave(event)" ondrop="handleDrop(event)">
                <!-- Cards go here -->
            </div>
        </div>

        <!-- Done Column -->
        <div class="column" id="col-done">
            <div class="column-header">
                <span>Done</span>
                <span class="count">0</span>
            </div>
            <div class="card-list" ondragover="handleDragOver(event)" ondragleave="handleDragLeave(event)" ondrop="handleDrop(event)">
                <!-- Cards go here -->
            </div>
        </div>
    </div>

    <script>
        const inputField = document.getElementById('new-card');
        const addBtn = document.getElementById('add-card');
        const columns = {
            todo: document.querySelector('#col-todo .card-list'),
            doing: document.querySelector('#col-drag-doing')?.parentElement ? null : null, // Placeholder logic
        };

        // Re-mapping columns properly for easier access
        const colContainers = {
            'col-todo': document.querySelector('#col-todo .card-list'),
            'col-doing': document.querySelector('#col-doing .card-list'),
            'col-done': document.querySelector('#col-done .card-list')
        };

        // Initialize app
        document.addEventListener('DOMContentLoaded', loadBoard);

        // --- Core Functions ---

        function createCardElement(text, id) {
            const card = document.createElement('div');
            card.className = 'card';
            card.draggable = true;
            card.id = id || 'card-' + Date.now();

            // Drag events for the card itself
            card.addEventListener('dragstart', (e) => {
                e.dataTransfer.setData('text/plain', card.id);
                setTimeout(() => card.classList.add('dragging'), 0);
            });

            card.addEventListener('dragend', () => {
                card.classList.remove('dragging');
                updateCounts();
                saveBoard();
            });

            const textSpan = document.createElement('span');
            textSpan.className = 'card-text';
            textSpan.textContent = text;

            const delBtn = document.createElement('button');
            delBtn.className = 'card-del';
            delBtn.innerHTML = '&times;';
            delBtn.onclick = () => {
                card.remove();
                updateCounts();
                saveBoard();
            };

            card.appendChild(textSpan);
            card.appendChild(delBtn);
            return card;
        }

        function addCard() {
            const text = inputField.value.trim();
            if (text === '') return;

            const newCard = createCardElement(text);
            colContainers['col-todo'].appendChild(newCard);

            inputField.value = '';
            updateCounts();
            saveBoard();
        }

        // --- Drag and Drop Handlers ---

        function handleDragOver(e) {
            e.preventDefault(); // Necessary to allow drop
            const targetList = e.currentTarget;
            targetList.parentElement.classList.add('drag-over');
        }

        function handleDragLeave(e) {
            e.currentTarget.parentElement.classList.remove('drag-over');
        }

        function handleDrop(e) {
            e.preventDefault();
            const list = e.currentTarget;
            const columnEl = list.parentElement;
            columnEl.classList.remove('drag-over');

            const cardId = e.dataTransfer.getData('text/plain');
            const draggedCard = document.getElementById(cardId);

            if (draggedCard) {
                list.appendChild(draggedCard);
                updateCounts();
                saveBoard();
            }
        }

        // --- State Management ---

        function updateCounts() {
            ['col-todo', 'col-doing', 'col-done'].forEach(id => {
                const container = document.querySelector(`#${id} .card-list`);
                const countEl = document.querySelector(`#${id} .count`);
                countEl.textContent = container.children.length;
            });
        }

        function saveBoard() {
            const state = {};
            ['col-todo', 'col-doing', 'col-done'].forEach(id => {
                const cards = [];
                const container = document.querySelector(`#${id} .card-list`);
                container.querySelectorAll('.card').forEach(card => {
                    cards.push({
                        id: card.id,
                        text: card.querySelector('.card-text').textContent
                    });
                });
                state[id] = cards;
            });
            localStorage.setItem('kanban-board-state', JSON.stringify(state));
        }

        function loadBoard() {
            const saved = localStorage.getItem('kanban-board-state');
            if (!saved) return;

            const state = JSON.parse(saved);
            Object.keys(state).forEach(colId => {
                const container = document.querySelector(`#${colId} .card-list`);
                state[colId].forEach(cardData => {
                    const card = createCardElement(cardData.text, cardData.id);
                    container.appendChild(card);
                });
            });
            updateCounts();
        }

        // --- Event Listeners ---

        addBtn.addEventListener('click', addCard);

        inputField.addEventListener('keypress', (e) => {
            if (e.key === 'Enter') addCard();
        });
    </script>
</body>
</html>
